    setIsLoggedIn(false);
    setActiveView('home');
  };

  const renderView = () => {
    switch (activeView) {
      case 'home':
        return <HomeView onOpenLogin={() => setIsLoginModalOpen(true)} onGoToEmergency={() => setActiveView('emergency')} />;
