            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-8">
          {/* Role Switcher */}
          <div className="flex p-1 bg-white/5 rounded-2xl mb-8 border border-white/5">
            <button 
              onClick={() => { setLoginType('citizen'); setError(null); }}
