                    placeholder={loginType === 'management' ? 'management@gmail.com' : 'name@example.com'}
                  />
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                </div>
              </div>

              <div className="space-y-2">
