import React, { useState } from 'react';
import Navbar from './components/Navbar';
import HomeView from './components/HomeView';
import AboutSection from './components/AboutSection';
import WorkingSection from './components/WorkingSection';
import DepartmentsSection from './components/DepartmentsSection';
import ProfileSection from './components/ProfileSection';
import EmergencySection from './components/EmergencySection';
import ManagementDashboard from './components/ManagementDashboard';
import Footer from './components/Footer';
import LoginModal from './components/LoginModal';
import ReportModal from './components/ReportModal';

export interface CivicReport {
  id: string;
  category: string;
  description: string;
  location: string;
  severity: 'Low' | 'Medium' | 'High';
  status: 'Reported' | 'Started' | 'In Progress' | 'Done';
  timestamp: string;
  citizenName: string;
  preview?: string;
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<'home' | 'about' | 'working' | 'departments' | 'profile' | 'emergency' | 'dashboard'>('home');
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userRole, setUserRole] = useState<'citizen' | 'management' | null>(null);
  const [currentUserName, setCurrentUserName] = useState<string>('');

  // Global Reports State
  const [reports, setReports] = useState<CivicReport[]>([
    {
      id: '#CS-9401',
      category: 'Street Lights',
      description: 'The light is flickering constantly at night causing safety concerns.',
      location: 'Main St. & 4th, Mumbai',
      severity: 'Medium',
      status: 'Done',
      timestamp: 'Oct 24, 2024',
      citizenName: 'Sushila'
    },
    {
      id: '#CS-8812',
      category: 'Roads & Potholes',
      description: 'Huge pothole dangerous for motorcyclists after recent rains.',
      location: 'Oakhaven Dr., Mumbai',
      severity: 'High',
      status: 'In Progress',
      timestamp: 'Oct 12, 2024',
      citizenName: 'Amit'
    }
  ]);

  const handleLogin = (role: 'citizen' | 'management', identifier: string) => {
    setIsLoggedIn(true);
    setUserRole(role);
    setCurrentUserName(identifier);
    setIsLoginModalOpen(false);
    if (role === 'management') {
      setActiveView('dashboard');
    } else {
      setActiveView('profile');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(null);
    setCurrentUserName('');
    setActiveView('home');
  };

  const addReport = (newReport: CivicReport) => {
    setReports(prev => [newReport, ...prev]);
  };

  const updateReportStatus = (id: string, newStatus: CivicReport['status']) => {
    setReports(prev => prev.map(report => 
      report.id === id ? { ...report, status: newStatus } : report
    ));
  };

  const renderView = () => {
    switch (activeView) {
      case 'home':
        return <HomeView onOpenLogin={() => setIsLoginModalOpen(true)} onGoToEmergency={() => setActiveView('emergency')} />;
      case 'about':
        return <AboutSection onOpenLogin={() => setIsLoginModalOpen(true)} />;
      case 'working':
        return <WorkingSection onOpenLogin={() => setIsLoginModalOpen(true)} />;
      case 'departments':
        return <DepartmentsSection onOpenLogin={() => setIsLoginModalOpen(true)} />;
      case 'profile':
        // Filter reports belonging to the current user
        const userReports = reports.filter(r => r.citizenName === currentUserName);
        return <ProfileSection reports={userReports} userName={currentUserName} />;
      case 'emergency':
        return <EmergencySection />;
      case 'dashboard':
        return <ManagementDashboard reports={reports} onUpdateStatus={updateReportStatus} />;
      default:
        return <HomeView onOpenLogin={() => setIsLoginModalOpen(true)} onGoToEmergency={() => setActiveView('emergency')} />;
    }
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-amber-500/30 selection:text-amber-500 flex flex-col">
      <Navbar 
        activeView={activeView} 
        onSetView={setActiveView} 
        onOpenLogin={() => setIsLoginModalOpen(true)} 
        onOpenReport={() => setIsReportModalOpen(true)}
        isLoggedIn={isLoggedIn}
        userRole={userRole}
        onLogout={handleLogout}
      />

      <main className="flex-grow pt-24">
        {renderView()}
      </main>

      <Footer />

      {/* Modals */}
      {isLoginModalOpen && (
        <LoginModal 
          onClose={() => setIsLoginModalOpen(false)} 
          onLogin={handleLogin}
        />
      )}

      {isReportModalOpen && (
        <ReportModal 
          onClose={() => setIsReportModalOpen(false)} 
          onReportSubmit={addReport}
          defaultCitizenName={currentUserName}
        />
      )}
    </div>
  );
};

export default App;

